precision highp float;

uniform float time;
uniform vec2 resolution;

float hash(vec2 p) {
    return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
}

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(
        mix(hash(i + vec2(0,0)), hash(i + vec2(1,0)), u.x),
        mix(hash(i + vec2(0,1)), hash(i + vec2(1,1)), u.x),
        u.y
    );
}

// Chorro individual con su propia velocidad y fase
float chorro(vec2 uv, float aspect, float offset, float speed,
             float phase, float yBase, float len, float grosor) {

    float chorroX = mod(offset * speed + phase, 1.8) - 0.4;

    float centerY = yBase
        + 0.19 * sin(uv.x * 2.5  - offset * 1.3  + phase)
        + 0.11 * sin(uv.x * 5.8  + offset * 2.4  - phase * 0.7)
        + 0.08 * sin(uv.x * 10.0 - offset * 3.5  + phase * 1.2)
        + 0.05 * cos(uv.x * 4.0  + offset * 1.6  + phase * 0.5)
        + 0.03 * sin(uv.x * 16.0 - offset * 5.0);

    float wiggleX = 0.08 * sin(uv.y * 3.5  - offset * 2.2 + phase)
                  + 0.05 * sin(uv.y * 8.0  + offset * 3.3 - phase)
                  + 0.02 * cos(uv.y * 14.0 - offset * 4.1);

    float uvx      = uv.x - wiggleX;
    float dxC      = uvx - chorroX;

    float inC = smoothstep(0.0, 0.05, dxC) *
                smoothstep(0.0, 0.05, chorroX + len - uvx);

    float taper = smoothstep(0.0, 0.09, dxC) *
                  smoothstep(0.0, 0.09, chorroX + len - uvx);

    float noiseEdge = noise(vec2(uv.x * 6.0 - offset * 2.5 + phase, uv.y * 4.0 + offset)) * 0.018
                    + noise(vec2(uv.x * 13.0 + offset * 1.5, uv.y * 7.0 - offset * 2.0 + phase)) * 0.010;

    // Variación de grosor a lo largo del chorro (pulsos)
    float pulse = 1.0 + 0.35 * sin(dxC * 28.0 - offset * 8.0 + phase)
                      + 0.15 * sin(dxC * 52.0 + offset * 5.0);

    float thickness = (grosor + grosor * 0.55 * taper + noiseEdge) * pulse;

    float distY = abs(uv.y - centerY);
    return smoothstep(thickness, thickness * 0.08, distY) * inC;
}

void main() {
    vec2 uv = gl_FragCoord.xy / resolution;
    float aspect = resolution.x / resolution.y;

    float offset = time * 0.15;

    // — 3 CHORROS con velocidades distintas —
    float c1 = chorro(uv, aspect, offset, 0.80, 0.00, 0.50, 0.34, 0.055);
    float c2 = chorro(uv, aspect, offset, 1.30, 2.09, 0.48, 0.28, 0.042);
    float c3 = chorro(uv, aspect, offset, 0.55, 4.18, 0.52, 0.40, 0.048);

    float chorroTotal = min(c1 + c2 + c3, 1.0);

    // — GOTAS más gruesas —
    float drops = 0.0;

    for (int i = 0; i < 26; i++) {
        float fi = float(i);

        float seedX     = hash(vec2(fi, 1.0));
        float seedSpeed = 0.25 + hash(vec2(fi, 3.0)) * 0.55;
        float seedSize  = 0.026 + hash(vec2(fi, 4.0)) * 0.036; // más gruesas
        float seedOrbit = 0.07 + hash(vec2(fi, 5.0)) * 0.12;
        float seedPhase = hash(vec2(fi, 7.0)) * 6.28;
        float seedLen   = 0.28 + hash(vec2(fi, 8.0)) * 0.18;

        // Cada gota sigue a uno de los 3 chorros
        float whichC  = floor(mod(fi, 3.0));
        float cSpeed  = whichC < 1.0 ? 0.80 : (whichC < 2.0 ? 1.30 : 0.55);
        float cPhase  = whichC < 1.0 ? 0.00 : (whichC < 2.0 ? 2.09 : 4.18);
        float cBase   = whichC < 1.0 ? 0.50 : (whichC < 2.0 ? 0.48 : 0.52);

        float chorroX = mod(offset * cSpeed + cPhase, 1.8) - 0.4;

        float dropX = mod(chorroX + seedX * seedLen
                      + offset * (0.6 + hash(vec2(fi, 6.0))) * 0.05, 1.8) - 0.4;

        float orbitSpeed = seedSpeed * (mod(fi, 2.0) < 1.0 ? 1.0 : -1.0);
        float angle = time * orbitSpeed * 1.5
                    + fi * 2.39996
                    + 0.7 * sin(time * seedSpeed * 0.9 + seedPhase);

        float dropCenterY = cBase
            + 0.19 * sin(dropX * 2.5  - offset * 1.3  + cPhase)
            + 0.11 * sin(dropX * 5.8  + offset * 2.4  - cPhase * 0.7)
            + 0.08 * sin(dropX * 10.0 - offset * 3.5  + cPhase * 1.2);

        float dropY    = dropCenterY + seedOrbit * sin(angle);
        float dropXpos = dropX + (seedOrbit * 0.55 / aspect) * cos(angle);

        vec2 diff = uv - vec2(dropXpos, dropY);
        diff.x *= aspect * 0.80;
        float d = length(diff);

        drops += smoothstep(seedSize, seedSize * 0.04, d);
        drops += smoothstep(seedSize * 2.2, seedSize, d) * 0.22;
    }

    drops = min(drops, 1.0);

    // — COLOR #6B1E1E —
    vec3 bloodDark  = vec3(0.267, 0.047, 0.047);
    vec3 bloodMain  = vec3(0.418, 0.118, 0.118);
    vec3 bloodLight = vec3(0.560, 0.190, 0.190);

    float lum = 0.5 + 0.5 * sin(uv.x * 8.0 - offset * 2.5 + uv.y * 3.0);

    vec3 colChorro = mix(bloodDark, bloodLight, 0.3 + 0.4 * lum);
    vec3 colDrop   = mix(bloodDark, bloodMain,  0.2 + 0.4 * lum);

    float mask = max(chorroTotal, drops);
    vec3 finalColor = mix(colDrop, colChorro, chorroTotal / (mask + 0.001)) * mask;

    gl_FragColor = vec4(finalColor, mask);
}

